class ServoMotorController:
    """
    Controller class for managing servo motor communication via serial port
    """
    
    def __init__(self, port=None, baudrate=115200):
        """
        Initialize the servo motor controller
        
        Args:
            port: Serial port (e.g., 'COM3' on Windows, '/dev/ttyUSB0' on Linux)
            baudrate: Communication baud rate (default: 115200)
        """
        self.port = port
        self.baudrate = baudrate
        self.serial_port = None
        self.is_connected = False
        self.protocols = ServoMotorProtocols()
        
        # Current states
        self.current_angles = {i: 0 for i in range(1, 17)}
        self.current_colors = {i: "RED" for i in range(1, 17)}
    
    @staticmethod
    def list_available_ports():
        """List all available serial ports"""
        ports = serial.tools.list_ports.comports()
        return [port.device for port in ports]
    
    def connect(self, port=None, baudrate=None):
        """
        Connect to the serial port
        
        Args:
            port: Serial port (optional, uses stored value if not provided)
            baudrate: Baud rate (optional, uses stored value if not provided)
        
        Returns:
            bool: True if connection successful, False otherwise
        """
        if port:
            self.port = port
        if baudrate:
            self.baudrate = baudrate
        
        try:
            if self.is_connected:
                self.disconnect()
            
            self.serial_port = serial.Serial(
                port=self.port,
                baudrate=self.baudrate,
                timeout=1
            )
            time.sleep(2)  # Wait for connection to stabilize
            
            self.is_connected = True
            print(f"✓ Connected to {self.port} at {self.baudrate} baud")
            return True
            
        except Exception as e:
            print(f"✗ Connection failed: {str(e)}")
            self.is_connected = False
            return False
    
    def disconnect(self):
        """Disconnect from the serial port"""
        try:
            if self.serial_port and self.is_connected:
                self.serial_port.close()
                self.is_connected = False
                print("Disconnected from serial port")
                return True
        except Exception as e:
            print(f"Disconnect error: {str(e)}")
        return False
    
    def send_hex_command(self, hex_string, description=""):
        """
        Send a hexadecimal command to the serial port
        
        Args:
            hex_string: Hex command string (e.g., "FFFF01070DE00D")
            description: Optional description for logging
        
        Returns:
            bool: True if command sent successfully
        """
        if not self.is_connected or not self.serial_port:
            print("Warning: Not connected to serial port")
            return False
        
        try:
            hex_bytes = bytes.fromhex(hex_string)
            self.serial_port.write(hex_bytes)
            if description:
                print(f"→ {description}: {hex_string}")
            return True
        except Exception as e:
            print(f"✗ Send error: {str(e)}")
            return False
    
    def set_motor_angle(self, motor_num, angle):
        """
        Set the angle of a specific motor
        
        Args:
            motor_num: Motor number (1-16)
            angle: Target angle in degrees
        
        Returns:
            bool: True if command sent successfully
        """
        if motor_num < 1 or motor_num > 16:
            print(f"Invalid motor number: {motor_num}")
            return False
        
        angle_str = str(angle)
        
        if angle_str in ServoMotorProtocols.ANGLE_PROTOCOLS[motor_num]:
            hex_cmd = ServoMotorProtocols.ANGLE_PROTOCOLS[motor_num][angle_str]
            if self.send_hex_command(hex_cmd, f"Motor {motor_num} → {angle}°"):
                self.current_angles[motor_num] = angle
                return True
        else:
            # Find nearest available angle
            available_angles = [int(a) for a in ServoMotorProtocols.ANGLE_PROTOCOLS[motor_num].keys()]
            nearest_angle = min(available_angles, key=lambda x: abs(x - angle))
            print(f"⚠ Angle {angle}° not available, using nearest: {nearest_angle}°")
            
            hex_cmd = ServoMotorProtocols.ANGLE_PROTOCOLS[motor_num][str(nearest_angle)]
            if self.send_hex_command(hex_cmd, f"Motor {motor_num} → {nearest_angle}°"):
                self.current_angles[motor_num] = nearest_angle
                return True
        
        return False
    
    def set_motor_color(self, motor_num, color):
        """
        Set the RGB color of a specific motor
        
        Args:
            motor_num: Motor number (1-16)
            color: Color name ("RED", "GREEN", "BLUE")
        
        Returns:
            bool: True if command sent successfully
        """
        if motor_num < 1 or motor_num > 16:
            print(f"Invalid motor number: {motor_num}")
            return False
        
        if color not in ServoMotorProtocols.COLOR_OPTIONS:
            print(f"Invalid color: {color}")
            return False
        
        hex_cmd = ServoMotorProtocols.RGB_PROTOCOLS[motor_num][color]
        if self.send_hex_command(hex_cmd, f"Motor {motor_num} → {color}"):
            self.current_colors[motor_num] = color
            return True
        
        return False
    
    def set_all_angles(self, angle, delay=0.05):
        """
        Set all motors to the same angle
        
        Args:
            angle: Target angle in degrees
            delay: Delay between commands (seconds)
        """
        for motor_num in range(1, 17):
            self.set_motor_angle(motor_num, angle)
            time.sleep(delay)
    
    def set_all_colors(self, color, delay=0.05):
        """
        Set all motors to the same color
        
        Args:
            color: Color name
            delay: Delay between commands (seconds)
        """
        for motor_num in range(1, 17):
            self.set_motor_color(motor_num, color)
            time.sleep(delay)
    
    def set_multiple_angles(self, angle_dict, delay=0.03):
        """
        Set multiple motors to specified angles
        
        Args:
            angle_dict: Dictionary {motor_num: angle}
            delay: Delay between commands (seconds)
        """
        for motor_num, angle in angle_dict.items():
            self.set_motor_angle(motor_num, angle)
            time.sleep(delay)
    
    def rainbow_wave(self, cycles=2, delay=0.5):
        """
        Perform rainbow wave effect
        
        Args:
            cycles: Number of wave cycles
            delay: Delay between color changes (seconds)
        """
        colors = ["RED", "GREEN", "BLUE"]
        
        for cycle in range(cycles):
            for offset in range(3):
                for i in range(16):
                    motor = i + 1
                    color = colors[(i + offset) % 3]
                    self.set_motor_color(motor, color)
                time.sleep(delay)
        
        print("Rainbow wave completed!")
    
    def color_cycle(self, delay=1.0):
        """
        Cycle through all colors on all motors
        
        Args:
            delay: Delay between color changes (seconds)
        """
        colors = ["RED", "GREEN", "BLUE"]
        
        for color in colors:
            self.set_all_colors(color)
            time.sleep(delay)
        
        print("Color cycle completed!")
    
    def stop_all(self):
        """Reset all motors to 0 degrees"""
        self.set_all_angles(0)
        print("All motors reset to 0°")


# Welcome sequence for face recognition integration
class WelcomeSequence:
    """
    Welcome motion sequence for when Mr. David is recognized
    """
    
    # Motion Process 1 - 2 seconds duration
    MOTION_PROCESS_1 = {
        1: 40, 2: 0, 3: 0, 4: -40,
        5: 0, 6: 0, 7: 20, 8: 0,
        9: 0, 10: 0, 11: 0, 12: -20,
        13: 0, 14: 0, 15: 0, 16: 0
    }
    
    # Motion Process 2 - 2 seconds duration
    MOTION_PROCESS_2 = {
        1: 20, 2: 20, 3: 0, 4: -20,
        5: -20, 6: 0, 7: 0, 8: 0,
        9: 0, 10: 0, 11: 0, 12: 0,
        13: 0, 14: 0, 15: 0, 16: 0
    }
    
    # Motion Process 3 - 2 seconds duration
    MOTION_PROCESS_3 = {
        1: -20, 2: 20, 3: 0, 4: 20,
        5: -20, 6: 0, 7: 20, 8: 0,
        9: 0, 10: 0, 11: 0, 12: 20,
        13: 0, 14: 0, 15: 0, 16: 0
    }
    
    @staticmethod
    def execute(controller, callback=None):
        """
        Execute the complete welcome sequence
        
        Args:
            controller: ServoMotorController instance
            callback: Optional callback function to report progress
        """
        def report(msg):
            print(msg)
            if callback:
                callback(msg)
        
        report("🎉 Starting Welcome Sequence for Mr. David!")
        
        # Set all RGB to RED
        report("Setting all RGB to RED...")
        controller.set_all_colors("RED")
        time.sleep(0.5)
        
        # Motion Process 1 (2 seconds)
        report("Motion Process 1...")
        controller.set_multiple_angles(WelcomeSequence.MOTION_PROCESS_1)
        time.sleep(2)
        
        # Motion Process 2 (2 seconds)
        report("Motion Process 2...")
        controller.set_multiple_angles(WelcomeSequence.MOTION_PROCESS_2)
        time.sleep(2)
        
        # Motion Process 3 (2 seconds)
        report("Motion Process 3...")
        controller.set_multiple_angles(WelcomeSequence.MOTION_PROCESS_3)
        time.sleep(2)
        
        # Rainbow wave effect (2 cycles)
        report("Rainbow wave effect (2 cycles)...")
        controller.rainbow_wave(cycles=2, delay=0.5)
        
        # Set all RGB to BLUE and hold for 10 seconds
        report("Setting all RGB to BLUE for 10 seconds...")
        controller.set_all_colors("BLUE")
        time.sleep(10)
        
        # Reset all motors to 0 degrees and wait 10 seconds
        report("Resetting all motors to 0° for 10 seconds...")
        controller.set_all_angles(0)
        time.sleep(10)
        
        report("✅ Welcome sequence completed!")


# Utility functions
def get_rgb_protocol(motor_num, color):
    """
    Get the hex protocol for RGB color
    
    Args:
        motor_num: Motor number (1-16)
        color: Color name ("RED", "GREEN", "BLUE")
    
    Returns:
        str: Hex protocol string
    """
    return ServoMotorProtocols.RGB_PROTOCOLS.get(motor_num, {}).get(color, None)


def get_angle_protocol(motor_num, angle):
    """
    Get the hex protocol for motor angle
    
    Args:
        motor_num: Motor number (1-16)
        angle: Angle in degrees
    
    Returns:
        str: Hex protocol string
    """
    return ServoMotorProtocols.ANGLE_PROTOCOLS.get(motor_num, {}).get(str(angle), None)


def print_all_protocols():
    """Print all available protocols for reference"""
    print("\n" + "="*60)
    print("RGB COLOR PROTOCOLS")
    print("="*60)
    
    for motor in range(1, 17):
        print(f"\nMotor {motor}:")
        for color, hex_code in ServoMotorProtocols.RGB_PROTOCOLS[motor].items():
            print(f"  {color}: {hex_code}")
    
    print("\n" + "="*60)
    print("ANGLE ROTATION PROTOCOLS")
    print("="*60)
    
    for motor in range(1, 17):
        print(f"\nMotor {motor}:")
        for angle, hex_code in ServoMotorProtocols.ANGLE_PROTOCOLS[motor].items():
            print(f"  {angle}°: {hex_code}")


